/**
 * LandingPage.js
 * Public landing page — visible only when NOT logged in.
 * Redirects to /map if already authenticated.
 *
 * Layout:
 *   Left  — headline copy + sub-description
 *   Right — Billboard frame with real photo slideshow + robot mascot + CTAs
 */
import React, { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";
import useAuthStore from "../store/authStore";
import "./LandingPage.css";

// ── Billboard photos (base64-embedded, no external dependency) ──────────────
const SLIDES = [
  { src: "data:image/jpeg;base64,", loc: "Bourguiba Ave · Tunis" },
  { src: "data:image/jpeg;base64,", loc: "Lac 2 · Tunis" },
  { src: "data:image/jpeg;base64,", loc: "La Marsa · Tunis" },
  { src: "data:image/jpeg;base64,", loc: "Istanbul · Turkey" },
];

export default function LandingPage() {
  const navigate    = useNavigate();
  const isAuthenticated = useAuthStore((s) => s.isAuthenticated);
  const [cur, setCur] = useState(0);

  // Redirect logged-in users straight to the map
  useEffect(() => {
    if (isAuthenticated) navigate("/map", { replace: true });
  }, [isAuthenticated, navigate]);

  // Cycle slides every 3 s
  useEffect(() => {
    const id = setInterval(() => setCur((c) => (c + 1) % SLIDES.length), 3000);
    return () => clearInterval(id);
  }, []);

  return (
    <div className="lp">
      {/* ── Navbar ── */}
      <nav className="lp-nav">
        <div className="lp-logo">
          <span className="lp-logo-dot" />
          <span className="lp-logo-text">DOOH</span>
          <span className="lp-logo-muted">Platform</span>
        </div>
      </nav>

      {/* ── Hero ── */}
      <div className="lp-hero">

        {/* Left: copy */}
        <div className="lp-left">
          <div className="lp-eyebrow">
            <span className="lp-green-dot" />
            Advertising made effortless
          </div>
          <h1 className="lp-h1">
            Book Digital<br />
            <em>Billboards</em><br />
            Across the City
          </h1>
          <p className="lp-sub">
            Schedule your ads on premium digital screens — real-time
            availability, instant booking, live display.
          </p>
        </div>

        {/* Right: billboard + robot + buttons */}
        <div className="lp-right">

          {/* Billboard frame */}
          <div className="lp-bb-frame">
            <div className="lp-bb-screen">
              {SLIDES.map((slide, i) => (
                <div
                  key={i}
                  className={`lp-slide${i === cur ? " active" : ""}`}
                  style={{ backgroundImage: `url(${slide.src})` }}
                >
                  <div className="lp-slide-overlay" />
                  <span className="lp-live-badge">● LIVE</span>
                  <div className="lp-slide-caption">{slide.loc}</div>
                </div>
              ))}
            </div>

            {/* Progress dots */}
            <div className="lp-dots">
              {SLIDES.map((_, i) => (
                <div
                  key={i}
                  className={`lp-dot${i === cur ? " active" : ""}`}
                />
              ))}
            </div>
          </div>

          {/* Billboard legs */}
          <div className="lp-bb-legs">
            <div className="lp-bb-leg" /><div className="lp-bb-leg" />
          </div>
          <div className="lp-bb-base" />

          {/* Robot + message + CTA buttons */}
          <div className="lp-robot-row">
            <div className="lp-robot-wrap">
              <RobotSVG />
            </div>
            <div className="lp-robot-content">
              <div className="lp-bubble">
                <strong>psst, up there! 👆</strong>
                <span>Tap Sign Up or Sign In</span>
              </div>
              <div className="lp-cta-row">
                <button
                  className="lp-btn-green"
                  onClick={() => navigate("/register")}
                >
                  Sign Up →
                </button>
                <button
                  className="lp-btn-outline"
                  onClick={() => navigate("/login")}
                >
                  Sign In
                </button>
              </div>
            </div>
          </div>

        </div>
      </div>
    </div>
  );
}

// ── Robot SVG component ──────────────────────────────────────────────────────
function RobotSVG() {
  return (
    <svg width="90" height="108" viewBox="0 0 90 108"
      xmlns="http://www.w3.org/2000/svg" style={{ overflow: "visible" }}>
      <g style={{ animation: "bodyBounce 2.2s ease-in-out infinite",
                  transformOrigin: "45px 90px" }}>
        <rect x="19" y="99" width="13" height="8" rx="4" fill="#334155"/>
        <rect x="38" y="99" width="13" height="8" rx="4" fill="#334155"/>
        <rect x="22" y="85" width="8"  height="17" rx="3" fill="#475569"/>
        <rect x="40" y="85" width="8"  height="17" rx="3" fill="#475569"/>
        <rect x="11" y="55" width="48" height="34" rx="8" fill="#334155"/>
        <rect x="17" y="62" width="16" height="9"  rx="3" fill="#1e293b"/>
        <circle cx="21" cy="67" r="1.8" fill="#10b981"/>
        <circle cx="27" cy="67" r="1.8" fill="#f59e0b"/>
        <circle cx="32" cy="67" r="1.5" fill="#ef4444"/>
        <rect x="17" y="75" width="34" height="4" rx="2" fill="#1e293b"/>
        <rect x="19" y="76" width="10" height="2" rx="1" fill="#2563eb"/>
        <g style={{ animation: "armWave 3s ease-in-out infinite",
                    transformOrigin: "11px 61px" }}>
          <rect x="3" y="57" width="10" height="7"  rx="3" fill="#475569"/>
          <rect x="4" y="59" width="8"  height="18" rx="3" fill="#475569"/>
        </g>
        <g style={{ animation: "armWave 3s .8s ease-in-out infinite",
                    transformOrigin: "59px 61px" }}>
          <rect x="57" y="57" width="10" height="7"  rx="3" fill="#475569"/>
          <rect x="58" y="59" width="8"  height="18" rx="3" fill="#475569"/>
        </g>
        <rect x="31" y="46" width="13" height="11" rx="3" fill="#475569"/>
        <g style={{ animation: "headWiggle 4s ease-in-out infinite",
                    transformOrigin: "38px 32px" }}>
          <rect x="16" y="15" width="38" height="33" rx="9" fill="#334155"/>
          <rect x="21" y="21" width="28" height="20" rx="4" fill="#0f172a"/>
          <g style={{ animation: "blink 3.5s ease-in-out infinite",
                      transformOrigin: "29px 31px" }}>
            <rect x="23" y="25" width="10" height="7" rx="3" fill="#2563eb"/>
            <circle style={{ animation: "eyeLookLeft 5s ease-in-out infinite" }}
              cx="28" cy="29" r="2.5" fill="#93c5fd"/>
          </g>
          <g style={{ animation: "doubleBlink 3.5s 1.2s ease-in-out infinite",
                      transformOrigin: "47px 31px" }}>
            <rect x="41" y="25" width="10" height="7" rx="3" fill="#2563eb"/>
            <circle style={{ animation: "eyeLookLeft 5s .3s ease-in-out infinite" }}
              cx="46" cy="29" r="2.5" fill="#93c5fd"/>
          </g>
          <path d="M24 38 Q38 45 52 38" fill="none"
            stroke="#10b981" strokeWidth="2" strokeLinecap="round"/>
          <rect x="35" y="7" width="4" height="10" rx="2" fill="#475569"/>
          <circle style={{ animation: "antennaPulse 1.5s ease-in-out infinite" }}
            cx="37" cy="5" r="4.5" fill="#2563eb"/>
        </g>
      </g>
    </svg>
  );
}
